// ==========================================
// 1. 三元坐标转直角坐标函数 (保持不变)
// ==========================================
const SQRT3_2 = 0.866025;
function toCartesian(ch4, c2h4, c2h2) {
  // 假设底边长 100
  let x = c2h4 + ch4 / 2;
  let y = ch4 * SQRT3_2;
  return [x, y];
}

// ==========================================
// 2. 定义杜瓦尔三角形区域 (标准 IEC 60599 坐标)
// ==========================================
const zones = [
  { name: 'PD', color: '#B4E1FF', points: [[98, 0, 2], [100, 0, 0], [98, 2, 0]] },
  { name: 'T1', color: '#C1FFC1', points: [[98, 2, 0], [80, 20, 0], [76, 20, 4], [96, 0, 4], [98, 0, 2]] },
  { name: 'T2', color: '#FFFACD', points: [[80, 20, 0], [50, 50, 0], [46, 50, 4], [76, 20, 4]] },
  { name: 'T3', color: '#FFD700', points: [[50, 50, 0], [0, 100, 0], [0, 85, 15], [35, 50, 15], [46, 50, 4]] },
  { name: 'D1', color: '#FFB6C1', points: [[87, 0, 13], [64, 23, 0], [0, 23, 0], [0, 0, 36]] },
  { name: 'D2', color: '#FF69B4', points: [[64, 23, 36], [74, 13, 7], [47, 40, 13], [31, 40, 29], [0, 71, 29], [0, 23, 100]] },
  { name: 'D+T', color: '#E6E6FA', points: [[96, 0, 4], [76, 20, 4], [46, 50, 4], [35, 50, 15], [0, 85, 15], [0, 71, 29], [31, 40, 29], [47, 40, 13], [64, 23, 13], [87, 0, 13]] }
];

// ==========================================
// 3. 从 Grafana 数据源动态提取最新值 (终极匹配版)
// ==========================================
let ch4_p = 0, c2h4_p = 0, c2h2_p = 0;

// 1. 获取数据源 (兼容不同版本的插件 API)
const seriesList = (typeof context !== 'undefined' && context.panel && context.panel.data && context.panel.data.series)
  ? context.panel.data.series
  : (typeof data !== 'undefined' && data.series ? data.series : []);

// 💡 调试神器：将数据打印到浏览器控制台
console.log("🚀 Grafana 传入的原始数据结构:", seriesList);

// 2. 暴力遍历提取数据
if (seriesList && seriesList.length > 0) {
  seriesList.forEach(series => {
    if (!series.fields) return;

    series.fields.forEach(field => {
      const name = field.name;
      // 兼容不同的底层数组读取方式
      const vals = field.values.buffer || field.values;

      if (!vals || vals.length === 0) return;

      // 取最新的一条数据 (数组的最后一个值)
      const lastVal = vals[vals.length - 1];

      // 过滤掉无效值
      if (lastVal === null || lastVal === undefined) return;

      // ⚠️ 关键修改：使用 includes 模糊匹配，防止 Grafana 自动追加后缀标签
      if (name.includes('CH4_pct')) ch4_p = lastVal;
      if (name.includes('C2H4_pct')) c2h4_p = lastVal;
      if (name.includes('C2H2_pct')) c2h2_p = lastVal;
    });
  });
}

console.log(`🎯 最终提取用于画点的值 -> CH4: ${ch4_p}, C2H4: ${c2h4_p}, C2H2: ${c2h2_p}`);

const transformerPoint = toCartesian(ch4_p, c2h4_p, c2h2_p);

// ==========================================
// 4. ECharts 配置
// ==========================================
return {
  tooltip: { trigger: 'item' },
  xAxis: { show: false, min: -20, max: 120 },
  yAxis: { show: false, min: -20, max: 80 },
  series: [
    // 渲染填充区域
    {
      type: 'custom',
      name: 'Zones',
      renderItem: (params, api) => {
        const zone = zones[params.dataIndex];
        const coords = zone.points.map(p => api.coord(toCartesian(p[0], p[1], p[2])));
        return {
          type: 'polygon',
          shape: { points: coords },
          style: api.style({ fill: zone.color, stroke: '#666', lineWidth: 1 })
        };
      },
      data: zones.map(z => z.name)
    },
    // 渲染刻度文字和轴标题
    {
      type: 'scatter',
      symbolSize: 0,
      label: {
        show: true,
        formatter: '{b}',
        fontSize: 14,
        color: '#333',
        // 新增：为文字添加白色描边，防止与背景色或边框线融为一体
        textBorderColor: '#ffffff',
        textBorderWidth: 2
      },
      data: [
        // 1. 轴标题 (将 rotate 全部修改为 0，保持水平横向显示)
        { name: 'CH4%', value: [12, 50], label: { rotate: 0, fontWeight: 'bold', fontSize: 16, color: '#000' } },
        { name: 'C2H4%', value: [88, 50], label: { rotate: 0, fontWeight: 'bold', fontSize: 16, color: '#000' } },
        { name: 'C2H2%', value: [50, -12], label: { rotate: 0, fontWeight: 'bold', fontSize: 16, color: '#000' } },        // 2. 左侧 CH4 刻度 (X轴向左平移量从 -3 增大到 -5)
        { name: '20', value: toCartesian(20, 0, 80).map((v, i) => i === 0 ? v - 5 : v) },
        { name: '40', value: toCartesian(40, 0, 60).map((v, i) => i === 0 ? v - 5 : v) },
        { name: '60', value: toCartesian(60, 0, 40).map((v, i) => i === 0 ? v - 5 : v) },
        { name: '80', value: toCartesian(80, 0, 20).map((v, i) => i === 0 ? v - 5 : v) },

        // 3. 右侧 C2H4 刻度 (X轴向右平移量从 +3 增大到 +5)
        { name: '20', value: toCartesian(80, 20, 0).map((v, i) => i === 0 ? v + 5 : v) },
        { name: '40', value: toCartesian(60, 40, 0).map((v, i) => i === 0 ? v + 5 : v) },
        { name: '60', value: toCartesian(40, 60, 0).map((v, i) => i === 0 ? v + 5 : v) },
        { name: '80', value: toCartesian(20, 80, 0).map((v, i) => i === 0 ? v + 5 : v) },

        // 4. 底部 C2H2 刻度 (Y轴向下平移量从 -3 增大到 -5)
        { name: '20', value: [80, -5] },
        { name: '40', value: [60, -5] },
        { name: '60', value: [40, -5] },
        { name: '80', value: [20, -5] }
      ]
    },
    // 第四层：实际气体检测数据点 (红点)
    {
      name: '当前状态',
      type: 'scatter',
      symbolSize: 15,
      itemStyle: { color: 'red', borderColor: '#fff', borderWidth: 2 },
      // 将原始的百分比数据一起绑定到这个点上
      data: [{
        value: transformerPoint,
        rawParams: { ch4: ch4_p, c2h4: c2h4_p, c2h2: c2h2_p }
      }],
      tooltip: {
        formatter: function (params) {
          const r = params.data.rawParams;
          return `<b>当前变压器状态</b><br/>CH4: ${r.ch4.toFixed(2)}%<br/>C2H4: ${r.c2h4.toFixed(2)}%<br/>C2H2: ${r.c2h2.toFixed(2)}%`;
        }
      }
    }
  ]
};

