import "influxdata/influxdb/schema"

from(bucket: "transformer")
  |> range(start: v.timeRangeStart, stop: v.timeRangeStop)
  |> filter(fn: (r) => r["_measurement"] == "transformer_001")
  |> filter(fn: (r) => r["_field"] == "CH4" or r["_field"] == "C2H2" or r["_field"] == "C2H4")
  |> last()  // 🌟 关键优化：先拿出最新的那一条数据，过滤掉没用的历史数据
  |> schema.fieldsAsCols()  // 🌟 用官方内置函数代替手动 pivot，自动处理缺失列的问题
  |> map(fn: (r) => {
      // 获取数值，如果没有则默认为 0
      ch4 = if exists r.CH4 then float(v: r.CH4) else 0.0
      c2h2 = if exists r.C2H2 then float(v: r.C2H2) else 0.0
      c2h4 = if exists r.C2H4 then float(v: r.C2H4) else 0.0
      total = ch4 + c2h2 + c2h4
      
      // 增加 total > 0 的判断，防止被除数为 0 导致新的报错
      return {
          _time: r._time,
          CH4_pct: if total > 0.0 then (ch4 / total) * 100.0 else 0.0,
          C2H2_pct: if total > 0.0 then (c2h2 / total) * 100.0 else 0.0,
          C2H4_pct: if total > 0.0 then (c2h4 / total) * 100.0 else 0.0
      }
  })

