// =====================================================
// IEC 三比值法故障诊断面板 — ECharts getOption 脚本
// 修改字体大小：搜索 font: 'XXpx'
// 修改卡片尺寸：修改下方「布局计算」区域
// =====================================================

// ===== 从 Grafana 数据帧中提取最新气体浓度 =====
const series = context.panel.data.series;
let H2 = 0, CH4 = 0, C2H2 = 0, C2H4 = 0, C2H6 = 0;

if (series && series.length > 0) {
  series[0].fields.forEach(f => {
    const v = f.values[f.values.length - 1];
    if (v == null) return;
    if (f.name === 'H2')   H2   = v;
    if (f.name === 'CH4')  CH4  = v;
    if (f.name === 'C2H2') C2H2 = v;
    if (f.name === 'C2H4') C2H4 = v;
    if (f.name === 'C2H6') C2H6 = v;
  });
}

// ===== 计算 IEC 三比值 =====
const r1 = H2   > 0 ? CH4  / H2   : 0;   // CH4  / H2
const r2 = C2H4 > 0 ? C2H2 / C2H4 : 0;   // C2H2 / C2H4
const r3 = C2H6 > 0 ? C2H4 / C2H6 : 0;   // C2H4 / C2H6

// ===== IEC 60599 编码规则 =====
const c1 = r1 < 0.1 ? 0 : r1 <= 1.0 ? 1 : 2;   // CH4/H2  : <0.1→0, 0.1~1→1, >1→2
const c2 = r2 < 0.1 ? 0 : r2 <= 3.0 ? 1 : 2;   // C2H2/C2H4: <0.1→0, 0.1~3→1, >3→2
const c3 = r3 < 1.0 ? 0 : r3 <= 3.0 ? 1 : 2;   // C2H4/C2H6: <1→0,   1~3→1,   >3→2

// ===== 故障类型查找表（IEC 60599 Table 1）=====
const faultTable = {
  '000': { name: '正常老化',          color: '#52c41a' },
  '100': { name: '局部放电',          color: '#fadb14' },
  '110': { name: '低能量放电',        color: '#fa8c16' },
  '010': { name: '低能量放电',        color: '#fa8c16' },
  '020': { name: '高能量放电',        color: '#ff4d4f' },
  '120': { name: '高能量放电',        color: '#ff4d4f' },
  '001': { name: '热故障 <150°C',    color: '#ffa940' },
  '002': { name: '热故障 150~300°C', color: '#fa8c16' },
  '101': { name: '热故障 300~700°C', color: '#ff4d4f' },
  '202': { name: '热故障 >700°C',    color: '#cf1322' },
};
const fault = faultTable[`${c1}${c2}${c3}`] || { name: '无法判断', color: '#8c8c8c' };

// ===== 主题色（自动适配 Grafana 深色/浅色）=====
const isDark   = context.grafana.theme.isDark;
const cardBg   = isDark ? '#1e2a3a' : '#ffffff';
const textMain = isDark ? '#e2e8f0' : '#1a202c';
const textSub  = isDark ? '#94a3b8' : '#718096';
const border   = isDark ? '#2d4a6a' : '#e2e8f0';

function codeColor(code) {
  return ['#52c41a', '#fadb14', '#ff4d4f'][code] || '#8c8c8c';
}

// ===== 布局计算（调整这里改卡片大小）=====
const W   = context.panel.chart.getWidth();
const H   = context.panel.chart.getHeight();
const pad = 10;                          // 卡片间距（px）
const cw  = (W - pad * 5) * 0.235;      // 比值卡片宽度
const dw  = (W - pad * 5) * 0.265;      // 诊断卡片宽度（稍宽）
const ch  = H * 0.75;                     // 卡片高度
const cy  = 8;                          // 卡片顶部偏移

// ===== 比值卡片生成函数 =====
function ratioCard(x, label, ratioVal, code) {
  const col = codeColor(code);
  return {
    type: 'group', x, y: cy,
    children: [
      // 卡片背景
      { type: 'rect',
        shape: { x: 0, y: 0, width: cw, height: ch, r: 10 },
        style: { fill: cardBg, stroke: border, lineWidth: 1.5 } },

      // 比值名称（如 CH4 / H2）
      { type: 'text',
        style: { x: cw/2, y: ch * 0.10, text: label,
                 textAlign: 'center', fill: textSub,
                 font: '15px sans-serif' } },               // ← 标签字体大小

      // 比值数值（如 0.6795）
      { type: 'text',
        style: { x: cw/2, y: ch * 0.42, text: ratioVal.toFixed(4),
                 textAlign: 'center', fill: textMain,
                 font: 'bold 28px "Courier New", monospace' } },  // ← 数值字体大小

      // "编码"小标签
      { type: 'text',
        style: { x: cw/2, y: ch * 0.63, text: '编  码',
                 textAlign: 'center', fill: textSub,
                 font: '13px sans-serif' } },               // ← 编码标签字体大小

      // 编码色块背景
      { type: 'rect',
        shape: { x: cw/2 - 22, y: ch * 0.72, width: 44, height: 36, r: 6 },
        style: { fill: col + '33', stroke: col, lineWidth: 2 } },

      // 编码数字（0 / 1 / 2）
      { type: 'text',
        style: { x: cw/2, y: ch * 0.72 + ch * 0.12, text: String(code),
                 textAlign: 'center', fill: col,
                 font: 'bold 22px sans-serif' } },          // ← 编码数字字体大小
    ]
  };
}

// ===== 拼装最终 ECharts option =====
const x1 = pad;
const x2 = x1 + cw + pad;
const x3 = x2 + cw + pad;
const x4 = x3 + cw + pad;

return {
  backgroundColor: 'transparent',
  graphic: [
    // 三个比值卡片
    ratioCard(x1, 'CH4 / H2',    r1, c1),
    ratioCard(x2, 'C2H2 / C2H4', r2, c2),
    ratioCard(x3, 'C2H4 / C2H6', r3, c3),

    // 诊断结果卡片
    {
      type: 'group', x: x4, y: cy,
      children: [
        // 卡片背景
        { type: 'rect',
          shape: { x: 0, y: 0, width: dw, height: ch, r: 10 },
          style: { fill: fault.color + '1a', stroke: fault.color, lineWidth: 2.5 } },

        // "诊断结果"标签
        { type: 'text',
          style: { x: dw/2, y: ch * 0.10, text: '诊 断 结 果',
                   textAlign: 'center', fill: textSub,
                   font: '15px sans-serif' } },              // ← 标签字体大小

        // 故障类型名称
        { type: 'text',
          style: { x: dw/2, y: ch * 0.40, text: fault.name,
                   textAlign: 'center', fill: fault.color,
                   font: 'bold 28px sans-serif' } },         // ← 故障名称字体大小

        // 编码组合
        { type: 'text',
          style: { x: dw/2, y: ch * 0.60,
                   text: `编码组合  [ ${c1},  ${c2},  ${c3} ]`,
                   textAlign: 'center', fill: textSub,
                   font: '14px "Courier New", monospace' } }, // ← 编码组合字体大小

        // 分隔线
        { type: 'line',
          shape: { x1: dw*0.12, y1: ch*0.70, x2: dw*0.88, y2: ch*0.70 },
          style: { stroke: border, lineWidth: 1 } },

        // 气体原始值（第一行）
        { type: 'text',
          style: { x: dw/2, y: ch * 0.78,
                   text: `H2:${H2.toFixed(1)}  CH4:${CH4.toFixed(1)}  C2H6:${C2H6.toFixed(1)}`,
                   textAlign: 'center', fill: textSub,
                   font: '13px monospace' } },               // ← 原始值字体大小

        // 气体原始值（第二行）
        { type: 'text',
          style: { x: dw/2, y: ch * 0.90,
                   text: `C2H2:${C2H2.toFixed(2)}  C2H4:${C2H4.toFixed(1)}`,
                   textAlign: 'center', fill: textSub,
                   font: '13px monospace' } },               // ← 原始值字体大小
      ]
    },
  ]
};
